customHandlers.cctvListHandler:
function(ctx) {
    let fetchJson = (url) => JSON.parse(req(url).content);
    let url = `https://api.cntv.cn/lanmu/columnSearch?p=${ctx.pg}&n=20&serviceId=tvcctv&t=json`;
    let json = fetchJson(url);
    let data = json;
    data = data["response"];
data = data["docs"];
    if (!Array.isArray(data)) data = [];
    return data.map(item => {
      let title = item["column_name"] || "无标题";
      let urlVal = (function(obj) { try { let v = obj; for (let p of ["lastVIDE","videoSharedCode"]) { if (v && typeof v === 'object') v = v[p]; else return '_'; } return v || '_'; } catch(e) { return '_'; } })(item);
      let pic = item["column_logo"] || "";
      let vod_id = `###${title}###${urlVal}###${pic}`;
      return { vod_id: vod_id, vod_name: title, vod_pic: pic };
    });
  }

customHandlers.cctvDetailHandler:
function(ctx) {
    let parts = ctx.vodId.split('###');
    if (parts.length < 3) return { list: [] };
    let title = parts[1];
    let lastVideo = parts[2];
    let logo = parts[3];
    if (lastVideo === '_') return { list: [] };
    let infoUrl = `https://api.cntv.cn/video/videoinfoByGuid?guid=${lastVideo}&serviceId=tvcctv`;
    let infoJson = JSON.parse(req(infoUrl).content);
    if (!infoJson.ctid) return { list: [] };
    let topicId = infoJson.ctid;
    let channel = infoJson.channel || '';
    let listUrl = `https://api.cntv.cn/NewVideo/getVideoListByColumn?id=${topicId}&d=&p=1&n=100&sort=desc&mode=0&serviceId=tvcctv&t=json`;
    let listJson = JSON.parse(req(listUrl).content);
    let videoList = [];
    for (let video of (listJson?.data?.list || [])) {
      let playId = video.pid || video.vid || video.guid;
      if (playId) videoList.push(`${video.title}$${playId}`);
    }
    if (videoList.length === 0) return { list: [] };
    let vod = {
      vod_id: ctx.vodId,
      vod_name: title,
      vod_pic: logo,
      type_name: channel,
      vod_play_from: 'CCTV',
      vod_play_url: videoList.join('#')
    };
    return { list: [vod] };
  }

customHandlers.cctvPlayHandler:
function(ctx) {
    let pid = ctx.id;
    let url = `https://vdn.apps.cntv.cn/api/getHttpVideoInfo.do?pid=${pid}`;
    let json = JSON.parse(req(url).content);
    let hls = json?.hls_url || '';
    return { parse: 0, playUrl: '', url: hls };
  }
